'use client';

import { useState } from 'react';
import Link from 'next/link';
import { usePathname, useRouter } from 'next/navigation';
import { motion } from 'framer-motion';
import {
  Flame, Hash, User,
  PenSquare, Shield, LogOut, Sun, Moon, Crown, Lock,
} from 'lucide-react';
import { useAuth } from '@/contexts/AuthContext';
import { useTheme } from '@/contexts/ThemeContext';
import UpgradeModal from '@/components/subscription/UpgradeModal';

export default function Sidebar() {
  const pathname = usePathname();
  const router = useRouter();
  const { currentUser, logout } = useAuth();
  const { toggleTheme, isDark } = useTheme();
  const [showUpgrade, setShowUpgrade] = useState(false);

  const navItems = [
    { href: '/topics', label: 'Chủ đề', icon: Hash },
    { href: '/profile', label: 'Trang cá nhân', icon: User },
  ];

  const isWriter = currentUser?.role === 'editor' || currentUser?.role === 'admin';
  const isReader = currentUser?.role === 'reader';
  const isPro = currentUser?.plan === 'pro';
  const isPendingPro = currentUser?.plan === 'pending_pro';

  const handleLogout = () => { logout(); router.push('/login'); };

  const handleWriteClick = () => {
    if (!currentUser) { router.push('/login'); return; }
    if (isPendingPro) {
      // Show a brief toast-like message — user is already pending
      alert('⏳ Yêu cầu của bạn đang chờ admin duyệt. Vui lòng đợi!');
      return;
    }
    if (isReader) { setShowUpgrade(true); return; }
    router.push('/article/create');
  };

  return (
    <>
      <aside
        className="fixed left-0 top-0 h-screen w-[275px] flex flex-col justify-between p-4 max-lg:hidden z-40"
        style={{ background: 'var(--bg-primary)' }}
      >
        {/* Top section */}
        <div>
          {/* Logo */}
          <Link href="/" className="flex items-center gap-2.5 px-3 py-2 mb-4">
            <div className="w-10 h-10 rounded-xl flex items-center justify-center" style={{ background: 'linear-gradient(135deg, #F97316, #EA580C)' }}>
              <Flame className="w-6 h-6 text-white" />
            </div>
            <span className="text-xl font-bold" style={{ color: 'var(--text-primary)' }}>
              News<span style={{ color: '#F97316' }}>X</span>
            </span>
          </Link>

          {/* Nav */}
          <nav className="space-y-1">
            {navItems.map((item) => {
              const isActive = item.href === '/' ? pathname === '/' : pathname.startsWith(item.href);
              const Icon = item.icon;
              return (
                <Link key={item.href} href={item.href}>
                  <motion.div
                    whileHover={{ scale: 1.02, x: 4 }}
                    whileTap={{ scale: 0.98 }}
                    className="flex items-center gap-4 px-4 py-3 rounded-xl relative"
                    style={{
                      background: isActive ? 'rgba(249,115,22,0.1)' : 'transparent',
                      color: isActive ? '#F97316' : 'var(--text-primary)',
                    }}
                  >
                    {isActive && (
                      <motion.div layoutId="sidebar-active"
                        className="absolute left-0 top-1/2 -translate-y-1/2 w-1 h-8 rounded-r-full"
                        style={{ background: '#F97316' }}
                      />
                    )}
                    <Icon className="w-5 h-5" />
                <span className={`text-[15px] flex-1 ${isActive ? 'font-bold' : 'font-medium'}`}>{item.label}</span>
                  </motion.div>
                </Link>
              );
            })}

            {/* Viết bài — hiện cho TẤT CẢ user đã login */}
            {currentUser && (
              <motion.button
                whileHover={{ scale: 1.02, x: 4 }}
                whileTap={{ scale: 0.98 }}
                onClick={handleWriteClick}
                className="flex items-center gap-4 px-4 py-3 rounded-xl w-full text-left"
                style={{
                  background: pathname === '/article/create' ? 'rgba(59,130,246,0.1)' : 'transparent',
                  color: pathname === '/article/create' ? '#3B82F6' : (isReader || isPendingPro) ? 'var(--text-secondary)' : 'var(--text-primary)',
                }}
              >
                <PenSquare className="w-5 h-5" />
                <span className="text-[15px] font-medium flex-1">Viết bài</span>
                {/* Pending approval badge */}
                {isPendingPro && (
                  <span className="flex items-center gap-1 text-[10px] px-2 py-0.5 rounded-full font-semibold"
                    style={{ background: 'rgba(245,158,11,0.12)', color: '#F59E0B' }}>
                    ⏳ Chờ duyệt
                  </span>
                )}
                {/* Reader lock badge */}
                {isReader && (
                  <span className="flex items-center gap-1 text-[10px] px-2 py-0.5 rounded-full font-semibold"
                    style={{ background: 'rgba(249,115,22,0.12)', color: '#F97316' }}>
                    <Lock className="w-2.5 h-2.5" />
                    Pro
                  </span>
                )}
              </motion.button>
            )}

            {/* Admin panel */}
            {currentUser?.role === 'admin' && (
              <Link href="/admin">
                <motion.div
                  whileHover={{ scale: 1.02, x: 4 }}
                  whileTap={{ scale: 0.98 }}
                  className="flex items-center gap-4 px-4 py-3 rounded-xl"
                  style={{
                    background: pathname.startsWith('/admin') ? 'rgba(139,92,246,0.1)' : 'transparent',
                    color: pathname.startsWith('/admin') ? '#8B5CF6' : 'var(--text-primary)',
                  }}
                >
                  <Shield className="w-5 h-5" />
                  <span className="text-[15px] font-medium">Admin</span>
                </motion.div>
              </Link>
            )}
          </nav>
        </div>

        {/* Bottom section */}
        <div className="space-y-1">
          {/* Theme toggle */}
          <button
            onClick={toggleTheme}
            className="flex items-center gap-4 w-full px-4 py-3 rounded-xl hover:bg-[var(--bg-hover-md)] transition-colors"
            style={{ color: 'var(--text-secondary)' }}
          >
            {isDark ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            <span className="text-[15px] font-medium">{isDark ? 'Chế độ sáng' : 'Chế độ tối'}</span>
          </button>

          {/* User info */}
          {currentUser ? (
            <div className="flex items-center gap-3 px-4 py-3 rounded-xl" style={{ background: 'var(--bg-secondary)' }}>
              <div className="relative shrink-0">
                <img src={currentUser.avatar} alt={currentUser.name} className="w-9 h-9 rounded-full" style={{ background: 'var(--border-primary)' }} />
                {/* Pro badge */}
                {(isPro || isWriter) && currentUser.role !== 'admin' && (
                  <div className="absolute -bottom-1 -right-1 w-4 h-4 rounded-full flex items-center justify-center" style={{ background: '#F97316' }}>
                    <Crown className="w-2.5 h-2.5 text-white" />
                  </div>
                )}
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-sm font-semibold truncate" style={{ color: 'var(--text-primary)' }}>{currentUser.name}</p>
                <p className="text-xs truncate" style={{ color: 'var(--text-secondary)' }}>
                  {currentUser.role === 'admin' ? '🛡️ Admin'
                    : isPro || isWriter ? '👑 Pro Writer'
                    : isPendingPro ? '⏳ Chờ duyệt Pro'
                    : '👤 Free'}
                </p>
              </div>
              <button
                onClick={handleLogout}
                title="Đăng xuất"
                className="p-2 rounded-lg hover:bg-red-500/10 transition-colors shrink-0"
                style={{ color: '#EF4444' }}
              >
                <LogOut className="w-4 h-4" />
              </button>
            </div>
          ) : (
            <Link href="/login">
              <motion.div
                whileHover={{ scale: 1.02, x: 4 }}
                whileTap={{ scale: 0.98 }}
                className="flex items-center gap-4 px-4 py-3 rounded-xl"
                style={{ background: '#F97316', color: '#fff' }}
              >
                <User className="w-5 h-5" />
                <span className="text-[15px] font-semibold">Đăng nhập</span>
              </motion.div>
            </Link>
          )}
        </div>
      </aside>

      {/* Upgrade Modal */}
      {showUpgrade && <UpgradeModal onClose={() => setShowUpgrade(false)} />}
    </>
  );
}
